"""Auto-generated MCP tool definitions — DO NOT EDIT BY HAND.

Generated by scripts/generate_mcp_tools.py from:
- agent-workers/agents/domain_registry.py (domain agent actions)
- scripts/connector_tool_keys.txt        (platform tool registry)

Imported at the bottom of mcp_server.py so the @mcp.tool decorators
register against the same FastMCP instance as the hand-written tools.

To regenerate:
    python3 scripts/generate_mcp_tools.py

Namespace filtering (introduced in 0.6.0):
    Setting LIGHTBULB_MCP_NAMESPACES=finance,crm,gmail (comma-separated)
    restricts the *generated* tools to only those matching one of the listed
    prefixes. Hand-written tools in mcp_server.py are always registered.

    Unset / empty string → all generated tools register (current behaviour).

    Why: 1005 tools × ~80 tokens per tool description = ~80k tokens spent
    on tools/list per Claude Code session before the LLM does anything.
    Most customers only need a handful of integrations; filtering cuts the
    cold-start payload by ~80%.
"""

from __future__ import annotations

import json
import logging
import os
import sys
from typing import Optional

from lightbulb.mcp_server import (
    _get_client,
    _format_result,
    _call_with_retry,
    _maybe_route_generated_connector_invoke,
    _maybe_route_generated_domain_dispatch,
    mcp,
)


def _load_allowed_namespaces() -> set[str] | None:
    """Parse LIGHTBULB_MCP_NAMESPACES once at module import.

    Returns:
        ``None`` → no filtering (every generated tool registers).
        ``set[str]`` → only tools whose first underscore-segment is in this set.
    """
    raw = os.environ.get("LIGHTBULB_MCP_NAMESPACES", "").strip()
    if not raw:
        return None
    namespaces = {part.strip().lower() for part in raw.split(",") if part.strip()}
    return namespaces or None


_ALLOWED_NAMESPACES: set[str] | None = _load_allowed_namespaces()
if _ALLOWED_NAMESPACES is not None:
    print(
        f"lightbulb-mcp: namespace filter active — generated tools restricted "
        f"to {sorted(_ALLOWED_NAMESPACES)} (hand-written tools always register)",
        file=sys.stderr,
    )


def _guarded_dispatch(domain: str, action: str, message: str, inputs: dict | None = None):
    routed = _maybe_route_generated_domain_dispatch(domain, action, message, inputs)
    if routed is not None:
        return routed
    return _get_client().dispatch(domain, action=action, message=message, inputs=inputs)


def _guarded_invoke_tool(tool_name: str, arguments: dict):
    routed = _maybe_route_generated_connector_invoke(tool_name, arguments)
    if routed is not None:
        try:
            return json.loads(routed)
        except json.JSONDecodeError:
            return {"reply": routed}
    return _get_client().invoke_tool(tool_name, arguments)


def _ns_tool(namespace: str):
    """Conditional ``@mcp.tool()`` decorator scoped to a known namespace.

    Each generated tool declares its namespace explicitly at codegen time
    (e.g. ``finance``, ``it_ops``, ``document_intelligence``, ``clio``,
    ``microsoft``) so multi-word names work without underscore-split
    ambiguity. Registers with FastMCP only when LIGHTBULB_MCP_NAMESPACES is
    unset OR the namespace is in the allow list. Skipped tools become a
    regular Python function (no MCP exposure) but stay importable.
    """
    def decorator(fn):
        if _ALLOWED_NAMESPACES is None or namespace.lower() in _ALLOWED_NAMESPACES:
            return mcp.tool()(fn)
        return fn
    return decorator
