def finance_lbo_model(message: str = "", target_company: Optional[str] = None, entry_multiple: Optional[float] = None, leverage_ratio: Optional[float] = None, hold_period_years: int = 5) -> str:
    """Build a leveraged buyout model for a target company. Outputs sources
& uses, debt schedule, returns waterfall (IRR, MOIC), sensitivity
tables, and an investment-committee-ready summary memo.
    Args:
        message: Free-text objective for the action.
        target_company (required): Target company name or ticker.
        entry_multiple: Entry EV/EBITDA multiple.
        leverage_ratio: Net debt / EBITDA at close.
        hold_period_years: Investment hold period (default 5 years).
    """
    inputs: dict = {}
    if target_company is not None:
        inputs['target_company'] = target_company
    if entry_multiple is not None:
        inputs['entry_multiple'] = entry_multiple
    if leverage_ratio is not None:
        inputs['leverage_ratio'] = leverage_ratio
    if hold_period_years is not None:
        inputs['hold_period_years'] = hold_period_years

    def _do():
        return _guarded_dispatch('finance', action='finance_lbo_model', message=message, inputs=inputs or None)
    return _format_result(_call_with_retry(_do))

