@_ns_tool('finance')
def finance_xero_close_books(message: str = "", period: Optional[str] = None, auto_post_threshold_usd: Optional[float] = None) -> str:
    """Run a month-end close on the connected Xero org. Reviews unreconciled
transactions, accruals, prepayments, and intercompany eliminations,
then proposes adjusting journals for human approval.
    Args:
        message: Free-text objective for the action.
        period: Period to close (YYYY-MM); defaults to last month.
        auto_post_threshold_usd: Auto-post journals smaller than this; queue larger ones for approval.
    """
    inputs: dict = {}
    if period is not None:
        inputs['period'] = period
    if auto_post_threshold_usd is not None:
        inputs['auto_post_threshold_usd'] = auto_post_threshold_usd

    def _do():
        return _guarded_dispatch('finance', action='xero_close_books', message=message, inputs=inputs or None)
    return _format_result(_call_with_retry(_do))

@_ns_tool('finance')
def finance_xero_ar_followup(message: str = "", aging_bucket: Optional[str] = None, min_amount_usd: Optional[float] = None, send: bool = False) -> str:
    """Triage Xero accounts receivable and draft customer-facing follow-up
messages for overdue invoices. Tone, urgency, and channel are tuned
to the customer's payment history.
    Args:
        message: Free-text objective for the action.
        aging_bucket: One of: '1-30', '31-60', '61-90', '90+'. Empty = all overdue.
        min_amount_usd: Only follow up on invoices above this amount.
        send: If true, send messages directly; otherwise return drafts for review.
    """
    inputs: dict = {}
    if aging_bucket is not None:
        inputs['aging_bucket'] = aging_bucket
    if min_amount_usd is not None:
        inputs['min_amount_usd'] = min_amount_usd
    if send is not None:
        inputs['send'] = send

    def _do():
        return _guarded_dispatch('finance', action='xero_ar_followup', message=message, inputs=inputs or None)
    return _format_result(_call_with_retry(_do))

